// ─── Metrics ──────────────────────────────────────────────────────────────────
function Metrics() {
  const ref = useRef<HTMLDivElement>(null);
  const [counted,setCounted] = useState(false);
  const [vals,setVals] = useState([0,0,0,0]);
  const data = [
    {target:3, suffix:"+",label:"Ideas in Development", sub:"Across gaming, entertainment & tech"},
    {target:1, suffix:"", label:"Active Build Track",   sub:"ShangoMaji · Flagship IP"},
    {target:2, suffix:"", label:"Team Members",         sub:"Founder-operated. No filler."},
    {target:2, suffix:"", label:"Years in the Lab",     sub:"And we're just getting started"},
  ];
  useEffect(()=>{
    if(!ref.current) return;
    let active=true;
    const rafIds:number[]=[];
    const toIds:ReturnType<typeof setTimeout>[]=[];
    const obs=new IntersectionObserver(([e])=>{
      if(e.isIntersecting&&!counted){
        setCounted(true);
        data.forEach(({target},i)=>{
          const dur=1500,t0=performance.now();
          const tick=(now: number)=>{
            if(!active) return;
            const p=Math.min((now-t0)/dur,1),ease=1-Math.pow(1-p,3);
            setVals(v=>{const n=[...v];n[i]=Math.floor(ease*target);return n;});
            if(p<1) rafIds[i]=requestAnimationFrame(tick);
            else setVals(v=>{const n=[...v];n[i]=target;return n;});
          };
          toIds[i]=setTimeout(()=>{rafIds[i]=requestAnimationFrame(tick);},i*90);
        });
      }
    },{threshold:0.5});
    obs.observe(ref.current);
    return()=>{
      active=false;
      obs.disconnect();
      toIds.forEach(id=>clearTimeout(id));
      rafIds.forEach(id=>cancelAnimationFrame(id));
    };
  },[counted]);

  return (
    <section aria-label="Company metrics" className="metrics-section" style={{borderTop:"1px solid var(--border)",borderBottom:"1px solid var(--border)",background:"var(--bg-deep)",position:"relative",overflow:"hidden"}}>
      <div aria-hidden="true" style={{position:"absolute",inset:0,background:"radial-gradient(ellipse 60% 100% at 0% 50%,rgba(91,168,245,0.04) 0%,transparent 55%), radial-gradient(ellipse 50% 100% at 100% 50%,rgba(224,64,160,0.04) 0%,transparent 55%)",pointerEvents:"none"}}/>
      <div ref={ref} style={{maxWidth:1120,margin:"0 auto",padding:"0 40px",display:"grid",gridTemplateColumns:"repeat(4,1fr)"}}>
        {data.map((d,i)=>(
          <div key={i}
            style={{padding:"38px 40px",borderRight:i<3?"1px solid var(--border)":"none",transition:"background 0.18s"}}
            onMouseEnter={e=>e.currentTarget.style.background="var(--gold-dim)"}
            onMouseLeave={e=>e.currentTarget.style.background="transparent"}
          >
            <div style={{fontFamily:"var(--ff-d)",fontWeight:900,fontSize:"2.5rem",letterSpacing:"-0.04em",lineHeight:1,background:"linear-gradient(135deg,var(--t1),var(--gold-lt))",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text",marginBottom:7}}>
              {vals[i]}{d.suffix}
            </div>
            <div style={{fontFamily:"var(--ff-m)",fontSize:"0.6rem",letterSpacing:"0.08em",color:"var(--t3)",textTransform:"uppercase",marginBottom:4}}>{d.label}</div>
            <div style={{fontSize:"0.77rem",color:"var(--t2)"}}>{d.sub}</div>
          </div>
        ))}
      </div>
    </section>
  );
}


